import { NavLink } from 'react-router-dom';
import s from './Friends.module.css'

const Friends = () => {
    return (
      <div className={s.friends}>
   <NavLink to ='/friends'>Friends</NavLink> 
        </div>
    
    )

}
export default Friends ;
